if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $('Auth Guard').first().json;
const action = (body.action || 'list').toLowerCase();
const esc = s => (s || '').replace(/'/g, "''");
let query = '';
let meta = { action };

switch (action) {
  case 'create':
  case 'upsert':
    query = `INSERT INTO gda_wargames (opp_id, opp_title, solicitation_number, scenario_name, scenario_type, our_strategy, competitor_1_name, competitor_1_strategy, competitor_1_strengths, competitor_1_weaknesses, competitor_2_name, competitor_2_strategy, competitor_2_strengths, competitor_2_weaknesses, competitor_3_name, competitor_3_strategy, evaluation_criteria, our_win_themes, our_discriminators, ghost_themes, risk_factors, recommended_actions, pwin_before, pwin_after, ai_analysis, status, updated_at)
      VALUES ('${esc(body.opp_id)}', '${esc(body.opp_title)}', '${esc(body.solicitation_number)}', '${esc(body.scenario_name || 'Untitled Wargame')}', '${esc(body.scenario_type || 'Competitive')}', '${esc(body.our_strategy)}', '${esc(body.competitor_1_name)}', '${esc(body.competitor_1_strategy)}', '${esc(body.competitor_1_strengths)}', '${esc(body.competitor_1_weaknesses)}', '${esc(body.competitor_2_name)}', '${esc(body.competitor_2_strategy)}', '${esc(body.competitor_2_strengths)}', '${esc(body.competitor_2_weaknesses)}', '${esc(body.competitor_3_name)}', '${esc(body.competitor_3_strategy)}', '${esc(body.evaluation_criteria)}', '${esc(body.our_win_themes)}', '${esc(body.our_discriminators)}', '${esc(body.ghost_themes)}', '${esc(body.risk_factors)}', '${esc(body.recommended_actions)}', ${parseInt(body.pwin_before) || 0}, ${parseInt(body.pwin_after) || 0}, '${esc(body.ai_analysis)}', '${esc(body.status || 'Draft')}', NOW())
      RETURNING *;`;
    meta.action = 'create';
    break;
  case 'update':
    const sets = [];
    for (const [k,v] of Object.entries(body)) {
      if (['id','action','auth_key','deploy_key'].includes(k)) continue;
      if (typeof v === 'number') sets.push(`${k} = ${v}`);
      else if (typeof v === 'string') sets.push(`${k} = '${esc(v)}'`);
    }
    sets.push('updated_at = NOW()');
    query = `UPDATE gda_wargames SET ${sets.join(', ')} WHERE id = ${parseInt(body.id) || 0} RETURNING *;`;
    break;
  case 'delete':
    query = `DELETE FROM gda_wargames WHERE id = ${parseInt(body.id) || 0} RETURNING id, scenario_name;`;
    break;
  case 'get':
    query = `SELECT * FROM gda_wargames WHERE id = ${parseInt(body.id) || 0};`;
    break;
  case 'by_opp':
    query = `SELECT * FROM gda_wargames WHERE opp_id = '${esc(body.opp_id)}' OR solicitation_number = '${esc(body.solicitation_number)}' ORDER BY updated_at DESC;`;
    break;
  default:
    query = `SELECT * FROM gda_wargames ORDER BY updated_at DESC LIMIT ${parseInt(body.limit) || 50};`;
    meta.action = 'list';
}
return [{ json: { query, meta } }];

const meta = $('Build Query').first().json.meta;
const rows = $input.all().map(i => i.json).filter(r => r.id !== undefined);
const resp = { status: 'ok', action: meta.action };
if (['create','upsert','update','get'].includes(meta.action)) resp.wargame = rows[0] || null;
else if (meta.action === 'delete') resp.deleted = rows[0] || null;
else { resp.wargames = rows; resp.count = rows.length; }
resp.timestamp = new Date().toISOString();
return [{ json: resp }];
